    def solve(self):
        t = int(input())
        for i in range(t):
            n = int(input())
            items = []
            for _ in range(n):
                w, v = map(int, input().split())
                items.append((w, v))
            k = int(input())
            memo = [[-1 for _ in range(k+1)] for _ in range(n)]
            ans = self.knapsack(memo, 0, k, items)
            print(ans)

    def knapsack(self, dp, i, w, items):
        if i == len(items) - 1:
            return items[i][1]
        if dp[i][w] != -1:
            return dp[i][w]
        take = items[i][1] + self.knapsack(dp, i + 1, w - items[i][0], items)
        notTake = 0 + self.knapsack(dp, i + 1, w, items)
        dp[i][w] = max(take, notTake)
        return dp[i][w]

    def main(self):
        self.solve()

