class Solution {
    void solve() {
        int t;
        cin >> t;
        for(int i = 0; i < t; i++) {
            int n;
            cin >> n;
            vector<pair<int, int>> items;
            for(int j = 0; j < n; j++) {
                int w, v;
                cin >> w >> v;
                items.push_back({w, v});
            }
            int k;
            cin >> k;
            vector<vector<int>> dp(n, vector<int>(k+1, -1));
            cout << knapsack(dp, 0, k, items) << endl;
        }
    }

    int knapsack(vector<vector<int>>& dp, int i, int w, vector<pair<int, int>>& items) {
        if(i == items.size() - 1) {
            return items[i].second;
        }
        if(dp[i][w] != -1) {
            return dp[i][w];
        }
        int take = items[i].second + knapsack(dp, i + 1, w - items[i].first, items);
        int notTake = 0 + knapsack(dp, i + 1, w, items);
        dp[i][w] = max(take, notTake);
        return dp[i][w];
    }

    void main() {
        solve();
    }

};

